from flask import Flask, request, jsonify
import jwt
from jwt import PyJWKClient
from functools import wraps

class JWTWrapper:
    def __init__(self, hs256_secret, rs256_jwks_url):
        self.hs256_secret = hs256_secret
        self.rs256_jwks_url = rs256_jwks_url
        self.jwk_client = PyJWKClient(rs256_jwks_url)

    def decode_token(self, token, algorithms):
        try:
            if 'RS256' in algorithms:
                signing_key = self.jwk_client.get_signing_key_from_jwt(token)
                return jwt.decode(token, signing_key.key, algorithms=algorithms)
            elif 'HS256' in algorithms:
                return jwt.decode(token, self.hs256_secret, algorithms=algorithms)
        except jwt.ExpiredSignatureError:
            raise Exception("Token has expired")
        except jwt.InvalidTokenError:
            raise Exception("Invalid token")
        return None

    def token_required(self, algorithms):
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                token = None
                if 'Authorization' in request.headers:
                    token = request.headers['Authorization'].split(" ")[1]
                if not token:
                    return jsonify({'message': 'Token is missing!'}), 401
                try:
                    payload = self.decode_token(token, algorithms)
                except Exception as e:
                    return jsonify({'message': str(e)}), 401
                return f(payload, *args, **kwargs)
            return decorated_function
        return decorator

app = Flask(__name__)
jwt_wrapper = JWTWrapper(hs256_secret='your_hs256_secret', rs256_jwks_url='https://yourdomain.com/.well-known/jwks.json')

@app.route('/protected', methods=['GET'])
@jwt_wrapper.token_required(algorithms=['HS256', 'RS256'])
def protected_route(payload):
    return jsonify({'message': 'This is a protected route', 'payload': payload})

